// Purpose: Define the User model for MongoDB
// Feature: Login Feature
// Author: Coder Agent
// Version: 1
const mongoose = require('mongoose');

const userSchema = new mongoose.Schema({
  email: {
    type: String,
    required: true,
    unique: true,
    lowercase: true
  },
  passwordHash: {
    type: String,
    required: true,
    select: false
  },
  role: {
    type: String,
    enum: ['customer', 'admin'],
    default: 'customer'
  },
  createdAt: { type: Date, default: Date.now },
  updatedAt: { type: Date, default: Date.now }
}, { timestamps: true });

module.exports = mongoose.model('User', userSchema);

// Purpose: Provide authentication services
// Feature: Login Feature
// Author: Coder Agent
// Version: 1
const bcrypt = require('bcrypt');
const jwt = require('../utils/jwt');
const User = require('../models/User');

const validateCredentials = async (email, password) => {
  const user = await User.findOne({ email });
  if (!user || !await bcrypt.compare(password, user.passwordHash)) {
    throw new Error('Invalid email or password');
  }
  return user;
};

const generateToken = (user) => {
  const payload = { userId: user._id, email: user.email, role: user.role };
  return jwt.sign(payload, process.env.JWT_SECRET, { expiresIn: process.env.JWT_EXPIRES_IN });
};

module.exports = {
  validateCredentials,
  generateToken
};

// Purpose: Handle authentication requests
// Feature: Login Feature
// Author: Coder Agent
// Version: 1
const express = require('express');
const router = express.Router();
const authService = require('../services/auth.service');
const validateMiddleware = require('../middleware/validate');

router.post('/', validateMiddleware.validateLogin, async (req, res) => {
  try {
    const { email, password } = req.body;
    const user = await authService.validateCredentials(email, password);
    const token = authService.generateToken(user);
    res.json({ token, user: { id: user._id, email: user.email, role: user.role } });
  } catch (error) {
    res.status(401).json({ error: error.message });
  }
});

module.exports = router;

// Purpose: Define authentication routes
// Feature: Login Feature
// Author: Coder Agent
// Version: 1
const express = require('express');
const authController = require('../controllers/auth.controller');

const router = express.Router();

router.use('/api/auth', authController);

module.exports = router;

// Purpose: Validate request data
// Feature: Login Feature
// Author: Coder Agent
// Version: 1
const express = require('express');
const router = express.Router();
const Joi = require('joi');

const validateLogin = (req, res, next) => {
  const schema = Joi.object({
    email: Joi.string().email().required(),
    password: Joi.string().min(8).required()
  });
  const { error } = schema.validate(req.body);
  if (error) return res.status(400).json({ error: 'Email and password are required' });
  next();
};

module.exports = {
  validateLogin
};
